import{_ as i,o as t,c as s,ak as e}from"./chunks/framework.oFDsBAuP.js";const k=JSON.parse('{"title":"cc-switch 配置接入","description":"使用 cc-switch 管理多品牌的 Claude Code 与 Codex 配置","frontmatter":{"title":"cc-switch 配置接入","description":"使用 cc-switch 管理多品牌的 Claude Code 与 Codex 配置"},"headers":[],"relativePath":"tools/cc-switch.md","filePath":"tools/cc-switch.md"}'),l={name:"tools/cc-switch.md"};function h(d,a,n,c,o,r){return t(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="cc-switch-配置接入" tabindex="-1">cc-switch 配置接入 <a class="header-anchor" href="#cc-switch-配置接入" aria-label="Permalink to &quot;cc-switch 配置接入&quot;">​</a></h1><p>cc-switch 是一个跨平台的 AI CLI 配置管理工具，可集中管理 Claude Code、Codex、Gemini CLI 等工具的提供商配置。接入 MiniToken（微词元） 后，可以用图形界面保存 API Key、切换 Base URL，并减少手动修改环境变量或配置文件的步骤。</p><h2 id="获取工具" tabindex="-1">获取工具 <a class="header-anchor" href="#获取工具" aria-label="Permalink to &quot;获取工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资源</th><th>地址</th></tr></thead><tbody><tr><td>GitHub 发布页</td><td><a href="https://github.com/farion1231/cc-switch/releases" target="_blank" rel="noreferrer">cc-switch/releases</a></td></tr><tr><td>官方文档</td><td><a href="https://ccswitch.lovable.app" target="_blank" rel="noreferrer">ccswitch.lovable.app</a></td></tr></tbody></table><h2 id="安装方式" tabindex="-1">安装方式 <a class="header-anchor" href="#安装方式" aria-label="Permalink to &quot;安装方式&quot;">​</a></h2><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><ol><li>打开 <a href="https://github.com/farion1231/cc-switch/releases" target="_blank" rel="noreferrer">Releases</a> 页面。</li><li>下载最新的 <code>.msi</code> 安装器并按提示安装。</li><li>如果不想安装，也可以下载 <code>.zip</code> 便携版，解压后运行 <code>cc-switch.exe</code>。</li></ol><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><p>推荐使用 Homebrew：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> farion1231/ccswitch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cc-switch</span></span></code></pre></div><p>也可以从 Releases 页面下载 <code>.dmg</code>，打开后将应用拖入「应用程序」。</p><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>Debian/Ubuntu 可下载 <code>.deb</code> 后安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dpkg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cc-switch_</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.deb</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span></span></code></pre></div><p>AppImage 版本可直接授权运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cc-switch_</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.AppImage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./cc-switch_*.AppImage</span></span></code></pre></div><p>Arch Linux 可通过 AUR 安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">paru</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cc-switch-bin</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yay</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cc-switch-bin</span></span></code></pre></div><h2 id="一键导入配置-推荐" tabindex="-1">一键导入配置（推荐） <a class="header-anchor" href="#一键导入配置-推荐" aria-label="Permalink to &quot;一键导入配置（推荐）&quot;">​</a></h2><p>在 MiniToken（微词元） 控制台可以直接生成 cc-switch 配置，适合大多数用户。</p><ol><li>进入「令牌管理」。</li><li>找到要接入的令牌，点击「聊天」按钮旁边的下拉按钮。</li><li>在应用列表中选择「CC Switch」。</li><li>选择导入配置类型，例如 Claude、Codex 或 Gemini。</li><li>填写配置名称和主模型。</li><li>点击打开或导入到 CC Switch，并按提示完成保存。</li></ol><p>导入完成后，在 cc-switch 中启用该配置，再重新启动对应 CLI 工具即可生效。</p><h2 id="手动配置" tabindex="-1">手动配置 <a class="header-anchor" href="#手动配置" aria-label="Permalink to &quot;手动配置&quot;">​</a></h2><p>在 cc-switch 中新增提供商时，建议按目标工具分别创建配置。</p><h3 id="claude-code-配置" tabindex="-1">Claude Code 配置 <a class="header-anchor" href="#claude-code-配置" aria-label="Permalink to &quot;Claude Code 配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>填写内容</th></tr></thead><tbody><tr><td>提供商名称</td><td><code>MiniToken（微词元） Claude</code></td></tr><tr><td>API Base URL</td><td><code>https://api.minitoken.vip</code></td></tr><tr><td>API Key</td><td>在 MiniToken（微词元） 控制台创建的 Claude Code 专用令牌</td></tr><tr><td>模型</td><td>按需选择可用 Claude 模型</td></tr></tbody></table><h3 id="codex-配置" tabindex="-1">Codex 配置 <a class="header-anchor" href="#codex-配置" aria-label="Permalink to &quot;Codex 配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>填写内容</th></tr></thead><tbody><tr><td>提供商名称</td><td><code>MiniToken（微词元） Codex</code></td></tr><tr><td>Base URL</td><td><code>https://api.minitoken.vip/v1</code></td></tr><tr><td>API Key</td><td>在 MiniToken（微词元） 控制台创建的 codex 专用令牌</td></tr><tr><td>Model</td><td>按需选择可用的 GPT 模型，例如 <code>gpt-5.4</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">注意</p><p>Claude Code 与 Codex 建议使用不同令牌组。创建密钥时请按工具用途选择对应分组，避免配置正确但调用失败。</p><p>其他工具配置类似。</p></div><h2 id="启用手动配置" tabindex="-1">启用手动配置 <a class="header-anchor" href="#启用手动配置" aria-label="Permalink to &quot;启用手动配置&quot;">​</a></h2><ol><li>在 cc-switch 的配置列表中选择刚创建的 MiniToken（微词元） 配置。</li><li>点击启用或设为当前使用。</li><li>关闭并重新启动对应 CLI 工具，让新配置生效。</li></ol><p>cc-switch 也支持系统托盘快速切换：右键点击托盘图标，选择目标工具分类，再选择要启用的提供商配置。</p><h2 id="常用功能" tabindex="-1">常用功能 <a class="header-anchor" href="#常用功能" aria-label="Permalink to &quot;常用功能&quot;">​</a></h2><ul><li>API 端点测速：比较不同提供商的延迟与可用性。</li><li>配置备份与恢复：修改配置前自动留存历史版本。</li><li>MCP 服务器管理：集中维护 Claude Code 等工具的 MCP 配置。</li><li>环境变量冲突检测：减少旧变量覆盖新配置的问题。</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="./claude-code.html">claude 配置接入</a></li><li><a href="./codex.html">codex 配置接入</a></li></ul>`,36)])])}const b=i(l,[["render",h]]);export{k as __pageData,b as default};
